from collections import Counter

ips = Counter()
with open('access.log') as f:
 for line in f:
 if 'POST /login' in line and ' 401 ' in line:
 ip = line.split()[0]
 ips[ip] += 1
for ip, count in ips.most_common():
 print(ip, count)

